def log_audit(user_id, action, success, details=None):
    log_entry = AuditLog(
        user_id=user_id,
        action=action,
        ip_address=request.remote_addr,
        user_agent=request.headers.get('User-Agent', '')[:255],
        success=success,
        details=details
    )
    db.session.add(log_entry)
    db.session.commit()

def login_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'user_id' not in session:
            return jsonify({'error': 'Authentication required'}), 401
        return f(*args, **kwargs)
    return decorated_function

def send_email(to_email, subject, body):
    try:
        msg = MIMEMultipart('alternative')
        msg['Subject'] = subject
        msg['From'] = SMTP_FROM_EMAIL
        msg['To'] = to_email
        
        text_part = MIMEText(body, 'plain')
        msg.attach(text_part)
        
        with smtplib.SMTP(SMTP_SERVER, SMTP_PORT) as server:
            server.starttls()
            if SMTP_USERNAME and SMTP_PASSWORD:
                server.login(SMTP_USERNAME, SMTP_PASSWORD)
            server.send_message(msg)
        return True
    except Exception as e:
        app.logger.error(f'Email sending failed: {str(e)}')
        return False

def generate_secure_token():
    return secrets.token_urlsafe(32)

def hash_token(token):
    return hashlib.sha256(token.encode()).hexdigest()

@app.route('/register', methods=['POST'])
def register():
    data = request.get_json()
    
    if not data or 'email' not in data or 'password' not in data:
        return jsonify({'error': 'Email and password required'}), 400
    
    email = data['email'].strip().lower()
    password = data['password']
    
    if not email or '@' not in email or len(email) > 255:
        return jsonify({'error': 'Invalid email format'}), 400
    
    if len(password) < 8:
        return jsonify({'error': 'Password must be at least 8 characters'}), 400
    
    if User.query.filter_by(email=email).first():
        return jsonify({'error': 'Email already registered'}), 400
    
    user = User(email=email)
    user.set_password(password)
    
    db.session.add(user)
    db.session.commit()
    
    log_audit(user.id, 'USER_REGISTERED', True)
    
    return jsonify({'message': 'User registered successfully', 'user_id': user.id}), 201

@app.route('/login', methods=['POST'])
def login():
    data = request.get_json()
    
    if not data or 'email' not in data or 'password' not in data:
        return jsonify({'error': 'Email and password required'}), 400
    
    email = data['email'].strip().lower()
    password = data['password']
    
    user = User.query.filter_by(email=email).first()
    
    if not user or not user.check_password(password):
        log_audit(None, 'LOGIN_FAILED', False, f'Email: {email}')
        return jsonify({'error': 'Invalid credentials'}), 401
    
    if user.mfa_enabled:
        mfa_code = data.get('mfa_code', '').strip()
        
        if not mfa_code:
            return jsonify({'error': 'MFA code required', 'mfa_required': True}), 401
        
        if not mfa_code.isdigit() or len(mfa_code) != 6:
            log_audit(user.id, 'LOGIN_FAILED_MFA', False, 'Invalid MFA code format')
            return jsonify({'error': 'Invalid MFA code'}), 401
        
        totp = pyotp.TOTP(user.mfa_secret)
        if not totp.verify(mfa_code, valid_window=1):
            log_audit(user.id, 'LOGIN_FAILED_MFA', False, 'Incorrect MFA code')
            return jsonify({'error': 'Invalid MFA code'}), 401
    
    session.clear()
    session['user_id'] = user.id
    session['email'] = user.email
    session.permanent = True
    
    log_audit(user.id, 'LOGIN_SUCCESS', True)
    
    return jsonify({'message': 'Login successful', 'user_id': user.id}), 200

@app.route('/logout', methods=['POST'])
@login_required
def logout():
    user_id = session.get('user_id')
    session.clear()
    log_audit(user_id, 'LOGOUT', True)
    return jsonify({'message': 'Logged out successfully'}), 200

@app.route('/mfa/enable', methods=['POST'])
@login_required
def enable_mfa():
    user_id = session.get('user_id')
    user = User.query.get(user_id)
    
    if not user:
        return jsonify({'error': 'User not found'}), 404
    
    if user.mfa_enabled:
        return jsonify({'error': 'MFA already enabled'}), 400
    
    secret = pyotp.random_base32()
    user.mfa_secret = secret
    
    totp = pyotp.TOTP(secret)
    provisioning_uri = totp.provisioning_uri(name=user.email, issuer_name='MFA System')
    
    db.session.commit()
    
    log_audit(user.id, 'MFA_SECRET_GENERATED', True)
    
    return jsonify({
        'message': 'MFA secret generated',
        'secret': secret,
        'provisioning_uri': provisioning_uri
    }), 200

@app.route('/mfa/verify', methods=['POST'])
@login_required
def verify_mfa():
    user_id = session.get('user_id')
    user = User.query.get(user_id)
    
    if not user:
        return jsonify({'error': 'User not found'}), 404
    
    if user.mfa_enabled:
        return jsonify({'error': 'MFA already enabled'}), 400
    
    if not user.mfa_secret:
        return jsonify({'error': 'MFA not initialized'}), 400
    
    data = request.get_json()
    mfa_code = data.get('mfa_code', '').strip()
    
    if not mfa_code or not mfa_code.isdigit() or len(mfa_code) != 6:
        return jsonify({'error': 'Invalid MFA code format'}), 400
    
    totp = pyotp.TOTP(user.mfa_secret)
    if not totp.verify(mfa_code, valid_window=1):
        log_audit(user.id, 'MFA_VERIFICATION_FAILED', False)
        return jsonify({'error': 'Invalid MFA code'}), 401
    
    user.mfa_enabled = True
    db.session.commit()
    
    log_audit(user.id, 'MFA_ENABLED', True)
    
    return jsonify({'message': 'MFA enabled successfully'}), 200

