@app.route('/reset-mfa', methods=['POST'])
def reset_mfa():
    data = request.get_json()
    
    if not data or 'email' not in data:
        return jsonify({'error': 'Email required'}), 400
    
    email = data['email'].strip().lower()
    
    if not email or '@' not in email:
        return jsonify({'error': 'Invalid email format'}), 400
    
    user = User.query.filter_by(email=email).first()
    
    if not user:
        log_audit(None, 'MFA_RESET_REQUESTED', False, f'Unknown email: {email}')
        return jsonify({'message': 'If the email exists, a reset link has been sent'}), 200
    
    if not user.mfa_enabled:
        log_audit(user.id, 'MFA_RESET_REQUESTED', False, 'MFA not enabled')
        return jsonify({'message': 'If the email exists, a reset link has been sent'}), 200
    
    MFAResetToken.query.filter_by(user_id=user.id, used=False).filter(
        MFAResetToken.expires_at > datetime.utcnow()
    ).update({'used': True})
    db.session.commit()
    
    token = generate_secure_token()
    token_hash = hash_token(token)
    
    reset_token = MFAResetToken(
        user_id=user.id,
        token_hash=token_hash,
        expires_at=datetime.utcnow() + timedelta(hours=1)
    )
    db.session.add(reset_token)
    db.session.commit()
    
    reset_link = f"{BASE_URL}/reset-mfa/confirm?token={token}"
    
    email_body = f"""
You have requested to reset your MFA settings.

Click the link below to disable MFA and regain access to your account:
{reset_link}

This link will expire in 1 hour.

If you did not request this reset, please ignore this email and your MFA settings will remain unchanged.
"""
    
    email_sent = send_email(user.email, 'MFA Reset Request', email_body)
    
    if email_sent:
        log_audit(user.id, 'MFA_RESET_REQUESTED', True)
    else:
        log_audit(user.id, 'MFA_RESET_REQUESTED', False, 'Email sending failed')
    
    return jsonify({'message': 'If the email exists, a reset link has been sent'}), 200

@app.route('/reset-mfa/confirm', methods=['GET', 'POST'])
def confirm_reset_mfa():
    token = request.args.get('token') if request.method == 'GET' else request.get_json().get('token')
    
    if not token:
        return jsonify({'error': 'Reset token required'}), 400
    
    token_hash = hash_token(token)
    
    reset_token = MFAResetToken.query.filter_by(
        token_hash=token_hash,
        used=False
    ).first()
    
    if not reset_token:
        log_audit(None, 'MFA_RESET_FAILED', False, 'Invalid or used token')
        return jsonify({'error': 'Invalid or expired reset token'}), 400
    
    if reset_token.expires_at < datetime.utcnow():
        reset_token.used = True
        db.session.commit()
        log_audit(reset_token.user_id, 'MFA_RESET_FAILED', False, 'Expired token')
        return jsonify({'error': 'Reset token has expired'}), 400
    
    user = reset_token.user
    
    user.mfa_enabled = False
    user.mfa_secret = None
    reset_token.used = True
    
    db.session.commit()
    
    log_audit(user.id, 'MFA_RESET_COMPLETED', True)
    
    return jsonify({
        'message': 'MFA has been disabled successfully',
        'email': user.email
    }), 200

